#!/bin/bash
m=$((0xffffffff << (32 - $2))); ip=$(IFS=. read -r a b c d <<< "$1"; echo "$(( (a<<24)+(b<<16)+(c<<8)+d ))"); net=$((ip & m)); br=$((net | (0xffffffff ^ m))); printf "%d.%d.%d.%d - %d.%d.%d.%d" $(( (net+1)>>24&255 )) $(( (net+1)>>16&255 )) $(( (net+1)>>8&255 )) $(( (net+1)&255 )) $(( (br-1)>>24&255 )) $(( (br-1)>>16&255 )) $(( (br-1)>>8&255 )) $(( (br-1)&255 ))
